# BEST PRACTICE: Bounded Beam Search with Value Heuristics
class BeamSearchAgent:
    def __init__(self, beam_width=3, max_depth=5):
        self.beam_width = beam_width
        self.max_depth = max_depth
        self.innings_log = []  # Track decision history

    def plan_batting_innings(self, wicket_status, target_score, deliveries_left):
        current_level = [{
            'state': wicket_status,
            'path': [],
            'value_score': self._evaluate_position(wicket_status, target_score)
        }]

        for depth in range(self.max_depth):
            next_level = []
            for node in current_level:
                # Generate child actions (shot selection, ball handling)
                children = self._generate_shots(node['state'])
                for child_action, child_state in children:
                    child_value = self._evaluate_position(child_state, target_score)
                    next_level.append({
                        'state': child_state,
                        'path': node['path'] + [child_action],
                        'value_score': child_value
                    })

            # CRITICAL: Keep only top-K branches by heuristic score
            current_level = sorted(next_level, key=lambda x: x['value_score'], reverse=True)[:self.beam_width]
            self.innings_log.append({'depth': depth, 'candidates': len(current_level)})

        return current_level[0]['path']  # Return best plan

    def _evaluate_position(self, state, target):
        # Heuristic: runs_rate_advantage + wickets_remaining_safety_margin
        return state.current_runs - state.balls_faced + state.wickets_remaining * 5

# ANTI-PATTERN: Unbounded Search (exponential explosion)
class NaivePlanningAgent:
    def plan_batting_innings(self, wicket_status, target_score):
        all_possible_paths = []  # ❌ Stores ALL branches: O(b^d) memory

        def explore_all(current_state, depth=0):
            if depth > 5:
                all_possible_paths.append(current_state.path)
                return

            for shot_option in ['defensive', 'aggressive', 'cautious', 'risky']:
                next_state = self._simulate_shot(current_state, shot_option)
                explore_all(next_state, depth + 1)  # ❌ No pruning, explores every branch

        explore_all(wicket_status)
        # At depth=5 with 4 shots: 4^5 = 1024 paths. At depth=10: 1,048,576 paths!
        return max(all_possible_paths, key=lambda p: self._score_path(p))
